src/HNTRSMarketplace.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721Receiver.sol";
import "@openzeppelin/contracts/token/common/ERC2981.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/interfaces/IERC2981.sol";

/**
 * @title HNTRSMarketplace
 * @dev NFT Marketplace for sports designs with fixed-price and auction support
 */
contract HNTRSMarketplace is IERC721Receiver, AccessControl, ReentrancyGuard {
    // Roles
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant FEE_MANAGER_ROLE = keccak256("FEE_MANAGER_ROLE");

    // Platform fee (2.5% = 250 basis points)
    uint256 public platformFeeBps = 250;
    address public feeRecipient;

    // Listing types
    enum ListingType { FixedPrice, Auction }

    // Listing structure
    struct Listing {
        uint256 listingId;
        address nftContract;
        uint256 tokenId;
        address seller;
        uint256 price;
        ListingType listingType;
        uint256 startTime;
        uint256 endTime;
        bool isActive;
        address highestBidder;
        uint256 highestBid;
    }

    // Offer structure
    struct Offer {
        uint256 offerId;
        address nftContract;
        uint256 tokenId;
        address offerer;
        uint256 amount;
        uint256 expiry;
        bool isActive;
    }

    // Mappings
    mapping(uint256 => Listing) public listings;
    mapping(uint256 => Offer) public offers;
    mapping(address => mapping(uint256 => uint256)) public nftToListing; // nftContract => tokenId => listingId
    mapping(uint256 => mapping(address => uint256)) public bids; // listingId => bidder => bidAmount

    // Counters
    uint256 private _listingIdCounter;
    uint256 private _offerIdCounter;

    // Events
    event Listed(
        uint256 indexed listingId,
        address indexed nftContract,
        uint256 indexed tokenId,
        address seller,
        uint256 price,
        ListingType listingType,
        uint256 endTime
    );
    event ListingCancelled(uint256 indexed listingId);
    event ListingSold(
        uint256 indexed listingId,
        address indexed buyer,
        address nftContract,
        uint256 tokenId,
        uint256 price
    );
    event BidPlaced(
        uint256 indexed listingId,
        address indexed bidder,
        uint256 amount
    );
    event BidWithdrawn(uint256 indexed listingId, address indexed bidder);
    event AuctionSettled(
        uint256 indexed listingId,
        address indexed winner,
        uint256 amount
    );
    event OfferMade(
        uint256 indexed offerId,
        address indexed nftContract,
        uint256 indexed tokenId,
        address offerer,
        uint256 amount,
        uint256 expiry
    );
    event OfferAccepted(uint256 indexed offerId);
    event OfferCancelled(uint256 indexed offerId);
    event PlatformFeeUpdated(uint256 newFeeBps);
    event FeeRecipientUpdated(address newRecipient);

    // Constructor
    constructor(address _feeRecipient) {
        feeRecipient = _feeRecipient;
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(FEE_MANAGER_ROLE, msg.sender);
    }

    /**
     * @dev Create a fixed-price listing
     */
    function createFixedPriceListing(
        address nftContract,
        uint256 tokenId,
        uint256 price,
        uint256 duration
    ) external nonReentrant returns (uint256) {
        require(price > 0, "Price must be > 0");
        require(duration > 0, "Duration must be > 0");

        // Transfer NFT to marketplace
        IERC721(nftContract).safeTransferFrom(msg.sender, address(this), tokenId);

        uint256 listingId = _listingIdCounter++;
        uint256 endTime = block.timestamp + duration;

        listings[listingId] = Listing({
            listingId: listingId,
            nftContract: nftContract,
            tokenId: tokenId,
            seller: msg.sender,
            price: price,
            listingType: ListingType.FixedPrice,
            startTime: block.timestamp,
            endTime: endTime,
            isActive: true,
            highestBidder: address(0),
            highestBid: 0
        });

        nftToListing[nftContract][tokenId] = listingId;

        emit Listed(listingId, nftContract, tokenId, msg.sender, price, ListingType.FixedPrice, endTime);

        return listingId;
    }

    /**
     * @dev Create an auction listing
     */
    function createAuctionListing(
        address nftContract,
        uint256 tokenId,
        uint256 reservePrice,
        uint256 duration
    ) external nonReentrant returns (uint256) {
        require(reservePrice > 0, "Reserve price must be > 0");
        require(duration >= 1 hours, "Duration must be at least 1 hour");

        // Transfer NFT to marketplace
        IERC721(nftContract).safeTransferFrom(msg.sender, address(this), tokenId);

        uint256 listingId = _listingIdCounter++;
        uint256 endTime = block.timestamp + duration;

        listings[listingId] = Listing({
            listingId: listingId,
            nftContract: nftContract,
            tokenId: tokenId,
            seller: msg.sender,
            price: reservePrice,
            listingType: ListingType.Auction,
            startTime: block.timestamp,
            endTime: endTime,
            isActive: true,
            highestBidder: address(0),
            highestBid: 0
        });

        nftToListing[nftContract][tokenId] = listingId;

        emit Listed(listingId, nftContract, tokenId, msg.sender, reservePrice, ListingType.Auction, endTime);

        return listingId;
    }

    /**
     * @dev Buy a fixed-price listing
     */
    function buyFixedPrice(uint256 listingId) external payable nonReentrant {
        Listing storage listing = listings[listingId];

        require(listing.isActive, "Listing not active");
        require(listing.listingType == ListingType.FixedPrice, "Not a fixed price listing");
        require(msg.value >= listing.price, "Insufficient payment");
        require(block.timestamp <= listing.endTime, "Listing expired");

        listing.isActive = false;
        delete nftToListing[listing.nftContract][listing.tokenId];

        // Process payment
        _processPayment(listing.seller, listing.nftContract, listing.tokenId, msg.value);

        // Transfer NFT to buyer
        IERC721(listing.nftContract).safeTransferFrom(address(this), msg.sender, listing.tokenId);

        // Refund excess payment
        if (msg.value > listing.price) {
            payable(msg.sender).transfer(msg.value - listing.price);
        }

        emit ListingSold(listingId, msg.sender, listing.nftContract, listing.tokenId, listing.price);
    }

    /**
     * @dev Place a bid on an auction
     */
    function placeBid(uint256 listingId) external payable nonReentrant {
        Listing storage listing = listings[listingId];

        require(listing.isActive, "Listing not active");
        require(listing.listingType == ListingType.Auction, "Not an auction");
        require(block.timestamp < listing.endTime, "Auction ended");
        require(msg.sender != listing.seller, "Seller cannot bid");
        require(msg.value > listing.highestBid, "Bid must be higher than current");
        require(msg.value >= listing.price, "Bid below reserve price");

        // Refund previous highest bidder
        if (listing.highestBidder != address(0)) {
            payable(listing.highestBidder).transfer(listing.highestBid);
        }

        // Update highest bid
        listing.highestBidder = msg.sender;
        listing.highestBid = msg.value;

        // Extend auction if bid in last 5 minutes
        if (listing.endTime - block.timestamp < 5 minutes) {
            listing.endTime = block.timestamp + 5 minutes;
        }

        emit BidPlaced(listingId, msg.sender, msg.value);
    }

    /**
     * @dev Settle an ended auction
     */
    function settleAuction(uint256 listingId) external nonReentrant {
        Listing storage listing = listings[listingId];

        require(listing.isActive, "Listing not active");
        require(listing.listingType == ListingType.Auction, "Not an auction");
        require(block.timestamp >= listing.endTime, "Auction not ended");
        require(listing.highestBidder != address(0), "No bids placed");

        listing.isActive = false;
        delete nftToListing[listing.nftContract][listing.tokenId];

        // Process payment
        _processPayment(listing.seller, listing.nftContract, listing.tokenId, listing.highestBid);

        // Transfer NFT to winner
        IERC721(listing.nftContract).safeTransferFrom(address(this), listing.highestBidder, listing.tokenId);

        emit AuctionSettled(listingId, listing.highestBidder, listing.highestBid);
    }

    /**
     * @dev Cancel a listing
     */
    function cancelListing(uint256 listingId) external nonReentrant {
        Listing storage listing = listings[listingId];

        require(listing.isActive, "Listing not active");
        require(msg.sender == listing.seller || hasRole(ADMIN_ROLE, msg.sender), "Not authorized");

        // Refund highest bidder if auction
        if (listing.listingType == ListingType.Auction && listing.highestBidder != address(0)) {
            payable(listing.highestBidder).transfer(listing.highestBid);
        }

        listing.isActive = false;
        delete nftToListing[listing.nftContract][listing.tokenId];

        // Return NFT to seller
        IERC721(listing.nftContract).safeTransferFrom(address(this), listing.seller, listing.tokenId);

        emit ListingCancelled(listingId);
    }

    /**
     * @dev Make an offer on an NFT
     */
    function makeOffer(
        address nftContract,
        uint256 tokenId,
        uint256 amount,
        uint256 duration
    ) external payable nonReentrant returns (uint256) {
        require(msg.value == amount, "Payment mismatch");
        require(amount > 0, "Amount must be > 0");
        require(duration >= 1 days, "Duration must be at least 1 day");

        uint256 offerId = _offerIdCounter++;
        uint256 expiry = block.timestamp + duration;

        offers[offerId] = Offer({
            offerId: offerId,
            nftContract: nftContract,
            tokenId: tokenId,
            offerer: msg.sender,
            amount: amount,
            expiry: expiry,
            isActive: true
        });

        emit OfferMade(offerId, nftContract, tokenId, msg.sender, amount, expiry);

        return offerId;
    }

    /**
     * @dev Accept an offer (NFT owner only)
     */
    function acceptOffer(uint256 offerId) external nonReentrant {
        Offer storage offer = offers[offerId];

        require(offer.isActive, "Offer not active");
        require(block.timestamp <= offer.expiry, "Offer expired");

        IERC721 nft = IERC721(offer.nftContract);
        require(nft.ownerOf(offer.tokenId) == msg.sender, "Not NFT owner");

        offer.isActive = false;

        // Process payment
        _processPayment(msg.sender, offer.nftContract, offer.tokenId, offer.amount);

        // Transfer NFT to offerer
        nft.safeTransferFrom(msg.sender, offer.offerer, offer.tokenId);

        emit OfferAccepted(offerId);
    }

    /**
     * @dev Cancel an offer
     */
    function cancelOffer(uint256 offerId) external nonReentrant {
        Offer storage offer = offers[offerId];

        require(offer.isActive, "Offer not active");
        require(msg.sender == offer.offerer, "Not offerer");

        offer.isActive = false;

        // Refund offerer
        payable(offer.offerer).transfer(offer.amount);

        emit OfferCancelled(offerId);
    }

    /**
     * @dev Process payment with royalties and platform fee
     */
    function _processPayment(
        address seller,
        address nftContract,
        uint256 tokenId,
        uint256 amount
    ) internal {
        // Calculate platform fee
        uint256 platformFee = (amount * platformFeeBps) / 10000;
        uint256 remaining = amount - platformFee;

        // Check for royalties (ERC-2981)
        (address royaltyRecipient, uint256 royaltyAmount) = IERC2981(nftContract).royaltyInfo(tokenId, remaining);

        if (royaltyAmount > 0 && royaltyRecipient != address(0)) {
            remaining -= royaltyAmount;
            payable(royaltyRecipient).transfer(royaltyAmount);
        }

        // Transfer platform fee
        if (platformFee > 0) {
            payable(feeRecipient).transfer(platformFee);
        }

        // Transfer remaining to seller
        payable(seller).transfer(remaining);
    }

    /**
     * @dev Update platform fee
     */
    function setPlatformFee(uint256 newFeeBps) external onlyRole(FEE_MANAGER_ROLE) {
        require(newFeeBps <= 1000, "Fee cannot exceed 10%");
        platformFeeBps = newFeeBps;
        emit PlatformFeeUpdated(newFeeBps);
    }

    /**
     * @dev Update fee recipient
     */
    function setFeeRecipient(address newRecipient) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newRecipient != address(0), "Invalid address");
        feeRecipient = newRecipient;
        emit FeeRecipientUpdated(newRecipient);
    }

    /**
     * @dev Get active listings
     */
    function getActiveListings(uint256 offset, uint256 limit) external view returns (Listing[] memory) {
        uint256 total = _listingIdCounter;
        uint256 count = 0;

        // Count active listings
        for (uint256 i = offset; i < total && count < limit; i++) {
            if (listings[i].isActive) {
                count++;
            }
        }

        // Create array
        Listing[] memory activeListings = new Listing[](count);
        uint256 index = 0;

        for (uint256 i = offset; i < total && index < count; i++) {
            if (listings[i].isActive) {
                activeListings[index] = listings[i];
                index++;
            }
        }

        return activeListings;
    }

    /**
     * @dev Get listings by seller
     */
    function getListingsBySeller(address seller) external view returns (Listing[] memory) {
        uint256 count = 0;

        for (uint256 i = 0; i < _listingIdCounter; i++) {
            if (listings[i].seller == seller && listings[i].isActive) {
                count++;
            }
        }

        Listing[] memory sellerListings = new Listing[](count);
        uint256 index = 0;

        for (uint256 i = 0; i < _listingIdCounter; i++) {
            if (listings[i].seller == seller && listings[i].isActive) {
                sellerListings[index] = listings[i];
                index++;
            }
        }

        return sellerListings;
    }

    // ERC721Receiver
    function onERC721Received(
        address,
        address,
        uint256,
        bytes calldata
    ) external pure override returns (bytes4) {
        return IERC721Receiver.onERC721Received.selector;
    }

    // Supports interface
    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(AccessControl)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }
}

