// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Burnable.sol";
import "@openzeppelin/contracts/token/common/ERC2981.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Strings.sol";

/**
 * @title HNTRSNFT
 * @dev Sports design NFT contract with royalties and role-based access
 */
contract HNTRSNFT is ERC721, ERC721URIStorage, ERC721Burnable, ERC2981, AccessControl {
    using Strings for uint256;

    // Roles
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");

    // Counter for token IDs
    uint256 private _tokenIdCounter;

    // Contract metadata
    string public contractURI;

    // Token types for sports designs
    enum TokenType { Single, Collection }

    // Token metadata
    struct TokenMeta {
        string name;
        string category; // "football", "basketball", etc.
        TokenType tokenType;
        uint256 collectionId; // 0 for single, > 0 for collection items
        address creator;
        uint256 mintedAt;
        bool isLazyMinted;
    }

    // Mapping from token ID to metadata
    mapping(uint256 => TokenMeta) public tokenMeta;

    // Collection info
    struct Collection {
        string name;
        string description;
        uint256 maxSupply;
        uint256 currentSupply;
        uint256 price;
        bool isActive;
    }

    mapping(uint256 => Collection) public collections;
    uint256 private _collectionIdCounter;

    // Events
    event NFTMinted(
        uint256 indexed tokenId,
        address indexed creator,
        string uri,
        string category,
        TokenType tokenType
    );
    event CollectionCreated(
        uint256 indexed collectionId,
        string name,
        uint256 maxSupply,
        uint256 price
    );
    event LazyMintCreated(uint256 indexed tokenId, address indexed creator);
    event LazyMintClaimed(uint256 indexed tokenId, address indexed claimer);

    // Constructor
    constructor(
        string memory _name,
        string memory _symbol,
        string memory _contractURI,
        address defaultAdmin
    ) ERC721(_name, _symbol) {
        contractURI = _contractURI;
        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
        _grantRole(MINTER_ROLE, defaultAdmin);
        _grantRole(PAUSER_ROLE, defaultAdmin);
    }

    /**
     * @dev Mint a single NFT
     */
    function mintSingle(
        address to,
        string memory uri,
        string memory name,
        string memory category,
        address royaltyRecipient,
        uint96 royaltyPercentage
    ) public onlyRole(MINTER_ROLE) returns (uint256) {
        uint256 tokenId = _tokenIdCounter++;
        _tokenIdCounter++;

        _safeMint(to, tokenId);
        _setTokenURI(tokenId, uri);

        // Set metadata
        tokenMeta[tokenId] = TokenMeta({
            name: name,
            category: category,
            tokenType: TokenType.Single,
            collectionId: 0,
            creator: _msgSender(),
            mintedAt: block.timestamp,
            isLazyMinted: false
        });

        // Set royalty (default 10% if not specified)
        if (royaltyRecipient != address(0)) {
            _setTokenRoyalty(tokenId, royaltyRecipient, royaltyPercentage);
        } else {
            _setTokenRoyalty(tokenId, _msgSender(), 1000); // 10%
        }

        emit NFTMinted(tokenId, to, uri, category, TokenType.Single);

        return tokenId;
    }

    /**
     * @dev Create a collection with multiple NFTs
     */
    function createCollection(
        string memory name,
        string memory description,
        uint256 maxSupply,
        uint256 price
    ) public onlyRole(MINTER_ROLE) returns (uint256) {
        uint256 collectionId = _collectionIdCounter++;
        _collectionIdCounter++;

        collections[collectionId] = Collection({
            name: name,
            description: description,
            maxSupply: maxSupply,
            currentSupply: 0,
            price: price,
            isActive: true
        });

        emit CollectionCreated(collectionId, name, maxSupply, price);

        return collectionId;
    }

    /**
     * @dev Mint from a collection
     */
    function mintFromCollection(
        address to,
        uint256 collectionId,
        string memory uri,
        address royaltyRecipient,
        uint96 royaltyPercentage
    ) public onlyRole(MINTER_ROLE) returns (uint256) {
        require(collections[collectionId].isActive, "Collection not active");
        require(
            collections[collectionId].currentSupply < collections[collectionId].maxSupply,
            "Collection sold out"
        );

        uint256 tokenId = _tokenIdCounter++;
        _tokenIdCounter++;

        _safeMint(to, tokenId);
        _setTokenURI(tokenId, uri);

        // Update collection supply
        collections[collectionId].currentSupply++;

        // Set metadata
        tokenMeta[tokenId] = TokenMeta({
            name: collections[collectionId].name,
            category: "collection",
            tokenType: TokenType.Collection,
            collectionId: collectionId,
            creator: _msgSender(),
            mintedAt: block.timestamp,
            isLazyMinted: false
        });

        // Set royalty
        if (royaltyRecipient != address(0)) {
            _setTokenRoyalty(tokenId, royaltyRecipient, royaltyPercentage);
        } else {
            _setTokenRoyalty(tokenId, _msgSender(), 1000); // 10%
        }

        emit NFTMinted(tokenId, to, uri, "collection", TokenType.Collection);

        return tokenId;
    }

    /**
     * @dev Create lazy mint (gas-efficient minting for marketplace)
     */
    function createLazyMint(
        string memory uri,
        string memory name,
        string memory category,
        uint256 collectionId,
        address royaltyRecipient,
        uint96 royaltyPercentage
    ) public onlyRole(MINTER_ROLE) returns (uint256) {
        uint256 tokenId = _tokenIdCounter++;
        _tokenIdCounter++;

        // Set metadata but don't mint yet
        tokenMeta[tokenId] = TokenMeta({
            name: name,
            category: category,
            tokenType: collectionId > 0 ? TokenType.Collection : TokenType.Single,
            collectionId: collectionId,
            creator: _msgSender(),
            mintedAt: block.timestamp,
            isLazyMinted: true
        });

        // Set royalty
        if (royaltyRecipient != address(0)) {
            _setTokenRoyalty(tokenId, royaltyRecipient, royaltyPercentage);
        } else {
            _setTokenRoyalty(tokenId, _msgSender(), 1000); // 10%
        }

        emit LazyMintCreated(tokenId, _msgSender());

        return tokenId;
    }

    /**
     * @dev Claim a lazy minted NFT
     */
    function claimLazyMint(uint256 tokenId, string memory uri) public payable {
        require(tokenMeta[tokenId].isLazyMinted, "Not a lazy mint");
        require(_ownerOf(tokenId) == address(0), "Already claimed");

        // If collection, check price and supply
        if (tokenMeta[tokenId].tokenType == TokenType.Collection) {
            uint256 collectionId = tokenMeta[tokenId].collectionId;
            require(collections[collectionId].isActive, "Collection not active");
            require(
                collections[collectionId].currentSupply < collections[collectionId].maxSupply,
                "Collection sold out"
            );
            require(msg.value >= collections[collectionId].price, "Insufficient payment");

            collections[collectionId].currentSupply++;
        }

        _safeMint(_msgSender(), tokenId);
        _setTokenURI(tokenId, uri);
        tokenMeta[tokenId].isLazyMinted = false;

        emit LazyMintClaimed(tokenId, _msgSender());
    }

    /**
     * @dev Batch mint multiple NFTs
     */
    function batchMint(
        address to,
        string[] memory uris,
        string[] memory names,
        string[] memory categories,
        address royaltyRecipient,
        uint96 royaltyPercentage
    ) public onlyRole(MINTER_ROLE) returns (uint256[] memory) {
        require(uris.length == names.length && names.length == categories.length, "Array length mismatch");

        uint256[] memory tokenIds = new uint256[](uris.length);

        for (uint256 i = 0; i < uris.length; i++) {
            tokenIds[i] = mintSingle(
                to,
                uris[i],
                names[i],
                categories[i],
                royaltyRecipient,
                royaltyPercentage
            );
        }

        return tokenIds;
    }

    /**
     * @dev Update contract URI
     */
    function setContractURI(string memory _contractURI) public onlyRole(DEFAULT_ADMIN_ROLE) {
        contractURI = _contractURI;
    }

    /**
     * @dev Get total minted supply
     */
    function totalSupply() public view returns (uint256) {
        return _tokenIdCounter;
    }

    /**
     * @dev Get tokens owned by address
     */
    function getTokensByOwner(address owner) public view returns (uint256[] memory) {
        uint256 balance = balanceOf(owner);
        uint256[] memory tokens = new uint256[](balance);
        uint256 index = 0;

        for (uint256 i = 0; i < _tokenIdCounter; i++) {
            if (_ownerOf(i) == owner) {
                tokens[index] = i;
                index++;
            }
        }

        return tokens;
    }

    /**
     * @dev Get collection details
     */
    function getCollection(uint256 collectionId) public view returns (
        string memory name,
        string memory description,
        uint256 maxSupply,
        uint256 currentSupply,
        uint256 price,
        bool isActive
    ) {
        Collection storage c = collections[collectionId];
        return (c.name, c.description, c.maxSupply, c.currentSupply, c.price, c.isActive);
    }

    // Overrides
    function tokenURI(uint256 tokenId)
        public
        view
        override(ERC721, ERC721URIStorage)
        returns (string memory)
    {
        return super.tokenURI(tokenId);
    }

    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(ERC721, ERC721URIStorage, ERC2981, AccessControl)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }

    function _update(address to, uint256 tokenId, address auth)
        internal
        override(ERC721)
        returns (address)
    {
        return super._update(to, tokenId, auth);
    }
}

